// Multi-item: process EVERY new RSS item, not just the first.
const out = [];
for (const it of $input.all()) {
  const i = it.json;
  const title = i.title || '';
  const link = i.link || i.guid || '';
  const ym = title.match(/\((\d{4})\)/);
  const year = ym ? ym[1] : null;
  const cleanTitle = title.replace(/\s*\(\d{4}\).*$/, '').trim();
  const nm = link.match(/\/(\d+)-/);
  const newsId = nm ? nm[1] : null;
  if (!cleanTitle || !year || !newsId) continue;
  out.push({ json: { cleanTitle, year, newsId, articleUrl: link } });
}
return out;

// Multi-item: pair each TMDb response with its Extract item by index.
// The HTTP node ran once per Extract output item, preserving order, so
// tmdbItems[idx] corresponds to extractItems[idx].
const tmdbItems = $input.all();
const extractItems = $('Extract 1080p Info').all();
const out = [];
for (let idx = 0; idx < tmdbItems.length; idx++) {
  const tmdb = tmdbItems[idx].json;
  const prev = extractItems[idx].json;
  const results = tmdb.results || [];
  if (!results.length) continue;
  const m = results[0];
  out.push({ json: {
    tmdbId: m.id, tmdbTitle: m.title,
    year: prev.year, newsId: prev.newsId,
    articleUrl: prev.articleUrl, cleanTitle: prev.cleanTitle
  }});
}
return out;

// Multi-item: build one Telegram notification per movie. The 4K RSS text is the
// same feed for every movie, so fetch it once outside the loop.
const movies = $('Process TMDb 1080p').all();
const rss4kResp = $('Fetch 4K RSS').first().json;
const rss4kText = typeof rss4kResp === 'string' ? rss4kResp : (rss4kResp.data || rss4kResp.body || '');
const itemsRaw = rss4kText.match(/<item>[\s\S]*?<\/item>/gi) || [];

const store = $getWorkflowStaticData('global');
if (!store.pending) store.pending = {};
// MarkdownV2 escape — now includes '-' (Telegram reserves it; the omission was
// crashing notifications for any title containing a hyphen).
const esc = s => String(s).replace(/([_*[\]()~`>#+\-=|{}\\.!])/g, '\\$1');

const out = [];
for (const mv of movies) {
  const prev = mv.json;

  let has4k = false, articleUrl4k = null, newsId4k = null;
  const word0 = prev.cleanTitle.toLowerCase().split(/\s+/)[0];
  for (const it of itemsRaw) {
    const tm = it.match(/<title>(.*?)<\/title>/);
    const lm = it.match(/<link>(.*?)<\/link>/) || it.match(/<guid[^>]*>(.*?)<\/guid>/);
    if (!tm || !lm) continue;
    const t4 = tm[1].replace(/&amp;/g, '&').replace(/&#39;/g, "'");
    if (t4.includes('(' + prev.year + ')') && t4.toLowerCase().includes(word0)) {
      has4k = true;
      articleUrl4k = lm[1];
      const n4m = lm[1].match(/\/(\d+)-/);
      newsId4k = n4m ? n4m[1] : null;
      break;
    }
  }

  const packageName = prev.tmdbTitle + ' (' + prev.year + ')';
  const oldMessageId = (store.pending[prev.newsId] || {}).messageId || null;

  store.pending[prev.newsId] = {
    articleUrl: prev.articleUrl, packageName,
    tmdbId: prev.tmdbId, cleanTitle: prev.cleanTitle, year: prev.year,
    has4k, articleUrl4k, newsId4k, messageId: oldMessageId, messageId4k: null
  };
  if (has4k && newsId4k) {
    if (!store.pending4k) store.pending4k = {};
    store.pending4k[newsId4k] = { articleUrl4k, packageName, newsId4k, messageId4k: null };
  }

  let keyboard;
  if (has4k) {
    keyboard = [
      [
        { text: '⬇️ 1080p',       callback_data: 'dl:'     + prev.newsId },
        { text: '⬇️ 1080p + 4K',  callback_data: 'dlboth:' + prev.newsId }
      ],
      [
        { text: '⬇️ 4K only',      callback_data: '4k:'    + newsId4k    },
        { text: '❌ Skip',               callback_data: 'skip:'  + prev.newsId }
      ]
    ];
  } else {
    keyboard = [[
      { text: '⬇️ Download 1080p', callback_data: 'dl:'   + prev.newsId },
      { text: '❌ Skip',                 callback_data: 'skip:' + prev.newsId }
    ]];
  }

  const msgText = '🎥 *' + esc(prev.tmdbTitle) + ' \\(' + prev.year + '\\)*' + (has4k ? '\n_4K x265 also available_' : '');

  let tgMethod, tgBody;
  if (oldMessageId) {
    tgMethod = 'editMessageText';
    tgBody = JSON.stringify({
      chat_id: '12373499',
      message_id: oldMessageId,
      text: msgText,
      parse_mode: 'MarkdownV2',
      reply_markup: { inline_keyboard: keyboard }
    });
  } else {
    tgMethod = 'sendMessage';
    tgBody = JSON.stringify({
      chat_id: '12373499',
      text: msgText,
      parse_mode: 'MarkdownV2',
      reply_markup: { inline_keyboard: keyboard }
    });
  }
  out.push({ json: { newsId: prev.newsId, tgBody, tgMethod } });
}
return out;

// Multi-item: each Telegram response pairs with the Prepare item of the same
// index (Send ran once per Prepare output, order preserved).
const responses = $input.all();
const prepared = $('Prepare Pending + Notify').all();
const store = $getWorkflowStaticData('global');
for (let idx = 0; idx < responses.length; idx++) {
  const resp = responses[idx].json;
  const newsId = prepared[idx] && prepared[idx].json ? prepared[idx].json.newsId : null;
  if (newsId && store.pending && store.pending[newsId] && resp.result) {
    store.pending[newsId].messageId = resp.result.message_id;
  }
}
return [{ json: { saved: responses.length } }];

const raw = $input.first().json;
const update = raw.body || raw;
const cq = update.callback_query;
if (!cq || !cq.data) return [];
const parts = cq.data.split(':');
const action = parts[0];
const newsId = parts.slice(1).join(':');
return [{ json: {
  action,
  newsId,
  callbackQueryId: cq.id,
  messageId: cq.message?.message_id,
  chatId: String(cq.message?.chat?.id || '12373499'),
  rawData: cq.data
}}];

const inp = $input.first().json;
const store = $getWorkflowStaticData('global');
const d = (store.pending || {})[inp.newsId];
if (!d || !d.articleUrl) return [];
// messageId: use inp (clicked message) not d (stored, may be stale)
return [{ json: { ...inp, ...d, messageId: inp.messageId } }];

const raw = $input.first().json;
const html = typeof raw === 'string' ? raw : (raw.data || raw.body || '');
const prev = $('Load 1080p Pending').first().json;
const unesc = html.replace(/&#(\d+);/g, (_,c) => String.fromCharCode(parseInt(c))).replace(/&amp;/g,'&');
const regex = /https?:\/\/filestore\.me\/[a-z0-9]+\/[^\s"'<>)]+\.(?:rar|rev)/gi;
const links = [...new Set(unesc.match(regex) || [])];
if (!links.length) return [];
return [{ json: { ...prev, links, linkString: links.join('\n'), count: links.length } }];

const inp = $input.first().json;
const store = $getWorkflowStaticData('global');
let newsId4k = inp.newsId;
let d = (store.pending4k || {})[newsId4k];
if (!d) {
  const p = (store.pending || {})[inp.newsId];
  if (p && p.newsId4k) {
    newsId4k = p.newsId4k;
    d = (store.pending4k || {})[newsId4k];
  }
}
if (!d || !d.articleUrl4k) return [];
// messageId: always use the clicked message from callback
return [{ json: { ...inp, ...d, newsId: newsId4k, messageId: inp.messageId } }];

const raw = $input.first().json;
const html = typeof raw === 'string' ? raw : (raw.data || raw.body || '');
const prev = $('Load 4K Pending').first().json;
const unesc = html.replace(/&#(\d+);/g, (_,c) => String.fromCharCode(parseInt(c))).replace(/&amp;/g,'&');
const regex = /https?:\/\/filestore\.me\/[a-z0-9]+\/[^\s"'<>)]+\.(?:rar|rev)/gi;
const links = [...new Set(unesc.match(regex) || [])];
if (!links.length) return [];
return [{ json: { ...prev, links, linkString: links.join('\n'), count: links.length } }];

const store = $getWorkflowStaticData('global');
const pending = store.pending || {};
const stuck = Object.entries(pending)
  .filter(([, d]) => !d.messageId)
  .map(([newsId, d]) => ({ json: { newsId, ...d } }));
if (!stuck.length) return [{ json: { noStuck: true } }];
return stuck;

const d = $input.first().json;
if (d.noStuck) return [];
let keyboard;
if (d.has4k) {
  keyboard = [
    [
      { text: '\u2b07\ufe0f 1080p',       callback_data: 'dl:'     + d.newsId },
      { text: '\u2b07\ufe0f 1080p + 4K',  callback_data: 'dlboth:' + d.newsId }
    ],
    [
      { text: '\u2b07\ufe0f 4K only',      callback_data: '4k:'    + d.newsId4k },
      { text: '\u274c Skip',                callback_data: 'skip:'  + d.newsId }
    ]
  ];
} else {
  keyboard = [[
    { text: '\u2b07\ufe0f Download 1080p', callback_data: 'dl:'   + d.newsId },
    { text: '\u274c Skip',                  callback_data: 'skip:' + d.newsId }
  ]];
}
const esc = s => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const title = d.cleanTitle || d.packageName;
const msgText = '\ud83c\udfa5 <b>' + esc(title) + ' (' + d.year + ')</b>'
  + (d.has4k ? '\n<i>4K x265 also available</i>' : '')
  + '\n<i>(recovery)</i>';
const tgBody = JSON.stringify({
  chat_id: '12373499',
  text: msgText,
  parse_mode: 'HTML',
  reply_markup: { inline_keyboard: keyboard }
});
return [{ json: { newsId: d.newsId, tgBody } }];

const resp = $input.first().json;
const newsId = $('Build Recovery Msg').first().json.newsId;
const store = $getWorkflowStaticData('global');
if (store.pending && store.pending[newsId] && resp.result) {
  store.pending[newsId].messageId = resp.result.message_id;
}
return [{ json: { saved: true, newsId, messageId: resp.result?.message_id } }];
